(function () {
    var input = document.getElementById('searchInput');
    var result = document.getElementById('searchResult');

    if (!input || !result || !window.SEARCH_INDEX) {
        return;
    }

    var params = new URLSearchParams(window.location.search);
    var initialQuery = params.get('q') || '';
    input.value = initialQuery;

    function normalizeText(value) {
        return String(value || '').toLowerCase().trim();
    }

    function card(movie) {
        var tags = movie.tags.slice(0, 3).map(function (tag) {
            return '<span>' + escapeHtml(tag) + '</span>';
        }).join('');

        return [
            '<article class="movie-card">',
            '<a class="movie-cover" href="' + escapeHtml(movie.url) + '">',
            '<img src="' + escapeHtml(movie.cover) + '" alt="' + escapeHtml(movie.title) + '" loading="lazy">',
            '<span class="cover-badge">' + escapeHtml(movie.year) + '</span>',
            '<span class="cover-play">▶</span>',
            '</a>',
            '<div class="movie-card-body">',
            '<div class="movie-meta-line"><span>' + escapeHtml(movie.category) + '</span><span>' + escapeHtml(movie.region) + '</span><span>' + escapeHtml(movie.type) + '</span></div>',
            '<h2><a href="' + escapeHtml(movie.url) + '">' + escapeHtml(movie.title) + '</a></h2>',
            '<p>' + escapeHtml(movie.oneLine) + '</p>',
            '<div class="tag-row">' + tags + '</div>',
            '</div>',
            '</article>'
        ].join('');
    }

    function escapeHtml(value) {
        return String(value || '')
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    function render() {
        var query = normalizeText(input.value);

        if (!query) {
            result.innerHTML = '';
            return;
        }

        var words = query.split(/\s+/).filter(Boolean);
        var matches = window.SEARCH_INDEX.filter(function (movie) {
            var haystack = normalizeText([
                movie.title,
                movie.year,
                movie.region,
                movie.type,
                movie.genre,
                movie.category,
                movie.tags.join(' '),
                movie.oneLine
            ].join(' '));

            return words.every(function (word) {
                return haystack.indexOf(word) !== -1;
            });
        }).slice(0, 120);

        result.innerHTML = matches.map(card).join('');
    }

    input.addEventListener('input', render);
    render();
})();
